mapper.insert:
INSERT INTO entry (
    transaction_id, account_id, debit, credit, account_type, created_at
) VALUES (
    #{transactionId}, #{accountId}, #{debit}, #{credit}, #{accountType}, #{createdAt}
)

mapper.select:
SELECT 
FROM entry
WHERE account_id = #{accountId}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COALESCE(SUM(debit), 0)
FROM entry
WHERE transaction_id = #{transactionId}

SELECT COALESCE(SUM(credit), 0)
FROM entry
WHERE transaction_id = #{transactionId}

SELECT COALESCE(SUM(e.debit), 0)
FROM entry e
INNER JOIN `transaction` t ON t.id = e.transaction_id AND t.is_deleted = 0
WHERE e.account_id = #{categoryId}
  AND e.account_type = 'category'
  AND t.date BETWEEN #{startDate} AND #{endDate}

SELECT COALESCE(SUM(e.credit), 0)
FROM entry e
INNER JOIN `transaction` t ON t.id = e.transaction_id AND t.is_deleted = 0
WHERE e.account_id = #{categoryId}
  AND e.account_type = 'category'
  AND t.date BETWEEN #{startDate} AND #{endDate}
